class Solution {
    public int maxScoreSightseeingPair(int[] values) {
        int maxScore = Integer.MIN_VALUE;
        int prevValue = values[0];
        for (int i = 1; i < values.length; i++) {
            maxScore = Math.max(maxScore, prevValue + values[i] + i - 1);
            prevValue = values[i];
        }
        return maxScore;
    }
}
